import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import ReactNativeBiometrics, { BiometryTypes } from 'react-native-biometrics';
import * as SecureStore from './SecureStore';
import { authApi } from '../services/authApi';

const AuthContext = createContext(null);

const rnBiometrics = new ReactNativeBiometrics({
  allowDeviceCredentials: false,
});

const SESSION_TOKEN_KEY = 'session_token';
const BIOMETRIC_KEY_EXISTS_KEY = 'biometric_key_exists';
const USER_ID_KEY = 'user_id';

export function AuthProvider({ children }) {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [hasBiometricKey, setHasBiometricKey] = useState(false);
  const [biometryType, setBiometryType] = useState(null);
  const [sessionToken, setSessionToken] = useState(null);
  const [userId, setUserId] = useState(null);

  useEffect(() => {
    initializeAuth();
  }, []);

  async function initializeAuth() {
    try {
      // Check what biometry is available
      const { available, biometryType: type } = await rnBiometrics.isSensorAvailable();
      if (available) {
        setBiometryType(type);
      }

      // Check if we have an existing biometric key registered
      const keyExists = await SecureStore.getItem(BIOMETRIC_KEY_EXISTS_KEY);
      setHasBiometricKey(keyExists === 'true');

      // Check if we have a valid session token in secure storage
      const storedToken = await SecureStore.getItem(SESSION_TOKEN_KEY);
      const storedUserId = await SecureStore.getItem(USER_ID_KEY);

      if (storedToken && storedUserId) {
        // Validate the session token with the backend
        const isValid = await authApi.validateSession(storedToken);
        if (isValid) {
          setSessionToken(storedToken);
          setUserId(storedUserId);
          setIsAuthenticated(true);
        } else {
          // Token expired or invalid — clear it
          await SecureStore.removeItem(SESSION_TOKEN_KEY);
          await SecureStore.removeItem(USER_ID_KEY);
        }
      }
    } catch (error) {
      console.error('Auth initialization error:', error);
    } finally {
      setIsLoading(false);
    }
  }

  /**
   * Standard password-based login.
   * On success, optionally enroll biometric key for future logins.
   */
  async function loginWithPassword(username, password, enrollBiometrics = false) {
    try {
      // Authenticate with the backend using credentials
      const response = await authApi.login(username, password);

      if (!response.success) {
        return { success: false, error: response.error || 'Invalid credentials' };
      }

      const { token, userId: uid } = response;

      // Store session token in secure storage (Keychain/Keystore)
      await SecureStore.setItem(SESSION_TOKEN_KEY, token);
      await SecureStore.setItem(USER_ID_KEY, uid);

      setSessionToken(token);
      setUserId(uid);
      setIsAuthenticated(true);

      // Optionally enroll biometric key
      if (enrollBiometrics && biometryType) {
        await enrollBiometricKey(uid, token);
      }

      return { success: true };
    } catch (error) {
      console.error('Login error:', error);
      return { success: false, error: 'An error occurred during login' };
    }
  }

  /**
   * Enroll a biometric keypair. The public key is sent to the server
   * and associated with the user's account. The private key remains
   * in the device's secure enclave / TEE, protected by biometrics.
   */
  async function enrollBiometricKey(uid, token) {
    try {
      // Delete any existing key first
      const { keysExist } = await rnBiometrics.biometricKeysExist();
      if (keysExist) {
        await rnBiometrics.deleteKeys();
      }

      // Create a new keypair — private key stored in Secure Enclave / TEE
      const { publicKey } = await rnBiometrics.createKeys();

      if (!publicKey) {
        console.warn('Failed to create biometric keys');
        return false;
      }

      // Register the public key with the backend
      const registered = await authApi.registerBiometricKey(token, uid, publicKey);

      if (registered.success) {
        await SecureStore.setItem(BIOMETRIC_KEY_EXISTS_KEY, 'true');
        await SecureStore.setItem(USER_ID_KEY, uid);
        setHasBiometricKey(true);
        return true;
      } else {
        // Cleanup if server registration failed
        await rnBiometrics.deleteKeys();
        return false;
      }
    } catch (error) {
      console.error('Biometric enrollment error:', error);
      return false;
    }
  }

  /**
   * Authenticate using biometrics.
   * 
   * SECURITY: This does NOT just set a boolean flag. Instead:
   * 1. We request a challenge nonce from the server.
   * 2. The biometric prompt signs the challenge using the private key
   *    stored in the Secure Enclave / TEE (requires biometric verification).
   * 3. The signed challenge (signature) is sent to the server.
   * 4. The server verifies the signature against the stored public key.
   * 5. Only if the server verifies successfully do we receive a session token.
   */
  async function authenticateWithBiometrics() {
    try {
      const storedUserId = await SecureStore.getItem(USER_ID_KEY);
      if (!storedUserId) {
        return { success: false, error: 'No user enrolled for biometric login' };
      }

      // Step 1: Request a challenge nonce from the server
      const challengeResponse = await authApi.requestBiometricChallenge(storedUserId);
      if (!challengeResponse.success) {
        return { success: false, error: 'Failed to get authentication challenge' };
      }

      const { challenge } = challengeResponse;

      // Step 2: Sign the challenge with biometric-protected private key
      // This triggers the Face ID / Fingerprint prompt
      const { success: signSuccess, signature } = await rnBiometrics.createSignature({
        promptMessage: 'Authenticate to sign in',
        payload: challenge,
        cancelButtonText: 'Use Password',
      });

      if (!signSuccess || !signature) {
        return { success: false, error: 'Biometric authentication cancelled or failed' };
      }

      // Step 3: Send the signature to the server for verification
      const verifyResponse = await authApi.verifyBiometricSignature(
        storedUserId,
        challenge,
        signature
      );

      if (!verifyResponse.success) {
        return { success: false, error: verifyResponse.error || 'Biometric verification failed on server' };
      }

      // Step 4: Server verified the signature — we have a real session token
      const { token } = verifyResponse;

      await SecureStore.setItem(SESSION_TOKEN_KEY, token);
      setSessionToken(token);
      setUserId(storedUserId);
      setIsAuthenticated(true);

      return { success: true };
    } catch (error) {
      console.error('Biometric authentication error:', error);

      if (error.message?.includes('cancelled') || error.message?.includes('user cancel')) {
        return { success: false, error: 'cancelled' };
      }

      return { success: false, error: 'Biometric authentication failed' };
    }
  }

  /**
   * Logout: clear session and optionally remove biometric keys.
   */
  async function logout(removeBiometricKeys = false) {
    try {
      // Invalidate session on the server
      if (sessionToken) {
        await authApi.logout(sessionToken).catch(() => {});
      }

      // Clear secure storage
      await SecureStore.removeItem(SESSION_TOKEN_KEY);

      if (removeBiometricKeys) {
        await SecureStore.removeItem(BIOMETRIC_KEY_EXISTS_KEY);
        await SecureStore.removeItem(USER_ID_KEY);
        await rnBiometrics.deleteKeys();
        setHasBiometricKey(false);
      }

      setSessionToken(null);
      setUserId(null);
      setIsAuthenticated(false);
    } catch (error) {
      console.error('Logout error:', error);
    }
  }

  /**
   * Unenroll biometric keys (e.g., from settings).
   * Requires current session to be authenticated.
   */
  async function unenrollBiometrics() {
    try {
      if (sessionToken) {
        await authApi.removeBiometricKey(sessionToken, userId);
      }
      await rnBiometrics.deleteKeys();
      await SecureStore.removeItem(BIOMETRIC_KEY_EXISTS_KEY);
      setHasBiometricKey(false);
      return true;
    } catch (error) {
      console.error('Unenroll biometrics error:', error);
      return false;
    }
  }

  const value = {
    isAuthenticated,
    isLoading,
    hasBiometricKey,
    biometryType,
    sessionToken,
    userId,
    loginWithPassword,
    authenticateWithBiometrics,
    enrollBiometricKey: async () => {
      if (sessionToken && userId) {
        return enrollBiometricKey(userId, sessionToken);
      }
      return false;
    },
    unenrollBiometrics,
    logout,
  };

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}


// context/SecureStore.js
// Wrapper around react-native-keychain for secure storage
// This uses the platform Keychain (iOS) / Keystore (Android)
// NOT AsyncStorage — values are encrypted at rest.
import * as Keychain from 'react-native-keychain';

const SERVICE_PREFIX = 'com.myapp.secure.';

export async function setItem(key, value) {
  try {
    await Keychain.setGenericPassword(key, value, {
      service: SERVICE_PREFIX + key,
      accessible: Keychain.ACCESSIBLE.WHEN_UNLOCKED_THIS_DEVICE_ONLY,
      securityLevel: Keychain.SECURITY_LEVEL.SECURE_HARDWARE,
    });
    return true;
  } catch (error) {
    console.error(`SecureStore setItem error for ${key}:`, error);
    return false;
  }
}

export async function getItem(key) {
  try {
    const credentials = await Keychain.getGenericPassword({
      service: SERVICE_PREFIX + key,
    });
    if (credentials) {
      return credentials.password;
    }
    return null;
  } catch (error) {
    console.error(`SecureStore getItem error for ${key}:`, error);
    return null;
  }
}

export async function removeItem(key) {
  try {
    await Keychain.resetGenericPassword({
      service: SERVICE_PREFIX + key,
    });
    return true;
  } catch (error) {
    console.error(`SecureStore removeItem error for ${key}:`, error);
    return false;
  }
}


// services/authApi.js
// Backend API service for authentication
// Replace BASE_URL with your actual backend URL

const BASE_URL = 'https://api.yourapp.com';

async function request(endpoint, options = {}) {
  const url = `${BASE_URL}${endpoint}`;
  const config = {
    headers: {
      'Content-Type': 'application/json',
      ...options.headers,
    },
    ...options,
  };

  try {
    const response = await fetch(url, config);
    const data = await response.json();

    if (!response.ok) {
      return { success: false, error: data.message || 'Request failed', status: response.status };
    }

    return { success: true, ...data };
  } catch (error) {
    console.error(`API request error (${endpoint}):`, error);
    return { success: false, error: 'Network error' };
  }
}

export const authApi = {
  /**
   * Standard username/password login
   * Returns: { success, token, userId }
   */
  async login(username, password) {
    return request('/auth/login', {
      method: 'POST',
      body: JSON.stringify({ username, password }),
    });
  },

  /**
   * Validate an existing session token
   * Returns: boolean
   */
  async validateSession(token) {
    const result = await request('/auth/validate', {
      method: 'POST',
      headers: { Authorization: `Bearer ${token}` },
    });
    return result.success;
  },

  /**
   * Register a biometric public key with the server
   * The server stores this public key associated with the user
   */
  async registerBiometricKey(token, userId, publicKey) {
    return request('/auth/biometric/register', {
      method: 'POST',
      headers: { Authorization: `Bearer ${token}` },
      body: JSON.stringify({ userId, publicKey }),
    });
  },

  /**
   * Request a challenge nonce for biometric authentication
   * The server generates a random nonce and stores it temporarily
   * Returns: { success, challenge }
   */
  async requestBiometricChallenge(userId) {
    return request('/auth/biometric/challenge', {
      method: 'POST',
      body: JSON.stringify({ userId }),
    });
  },

  /**
   * Verify a biometric signature
   * The server:
   * 1. Retrieves the stored public key for the user
   * 2. Retrieves the stored challenge nonce
   * 3. Verifies the signature matches challenge + public key
   * 4. If valid, issues a new session token
   * Returns: { success, token }
   */
  async verifyBiometricSignature(userId, challenge, signature) {
    return request('/auth/biometric/verify', {
      method: 'POST',
      body: JSON.stringify({ userId, challenge, signature }),
    });
  },

  /**
   * Remove biometric key from server
   */
  async removeBiometricKey(token, userId) {
    return request('/auth/biometric/remove', {
      method: 'POST',
      headers: { Authorization: `Bearer ${token}` },
      body: JSON.stringify({ userId }),
    });
  },

  /**
   * Logout / invalidate session
   */
  async logout(token) {
    return request('/auth/logout', {
      method: 'POST',
      headers: { Authorization: `Bearer ${token}` },
    });
  },
};


