import React, { useEffect, useState } from 'react';
import {
  View,
  Text,
  TouchableOpacity,
  StyleSheet,
  Alert,
  ActivityIndicator,
} from 'react-native';
import { BiometryTypes } from 'react-native-biometrics';
import { useAuth } from '../context/AuthContext';

export default function BiometricScreen({ navigation }) {
  const { authenticateWithBiometrics, biometryType, hasBiometricKey } = useAuth();
  const [isAuthenticating, setIsAuthenticating] = useState(false);

  useEffect(() => {
    // Automatically prompt biometrics on screen load
    if (hasBiometricKey) {
      handleBiometricAuth();
    }
  }, []);

  function getBiometryLabel() {
    switch (biometryType) {
      case BiometryTypes.FaceID:
        return 'Face ID';
      case BiometryTypes.TouchID:
        return 'Touch ID';
      case BiometryTypes.Biometrics:
        return 'Fingerprint';
      default:
        return 'Biometrics';
    }
  }

  function getBiometryIcon() {
    switch (biometryType) {
      case BiometryTypes.FaceID:
        return '👤';
      case BiometryTypes.TouchID:
      case BiometryTypes.Biometrics:
        return '👆';
      default:
        return '🔐';
    }
  }

  async function handleBiometricAuth() {
    if (isAuthenticating) return;

    setIsAuthenticating(true);
    try {
      const result = await authenticateWithBiometrics();

      if (!result.success) {
        if (result.error === 'cancelled') {
          // User cancelled — do nothing, they can tap again or use password
        } else {
          Alert.alert(
            'Authentication Failed',
            result.error || 'Please try again or use your password.',
            [
              { text: 'Try Again', onPress: handleBiometricAuth },
              { text: 'Use Password', onPress: navigateToLogin },
            ]
          );
        }
      }
      // If success, the auth context will update and navigation will handle the rest
    } catch (error) {
      console.error('Biometric auth error:', error);
    } finally {
      setIsAuthenticating(false);
    }
  }

  function navigateToLogin() {
    navigation.navigate('Login');
  }

  return (
    <View style={styles.container}>
      <View style={styles.content}>
        <Text style={styles.icon}>{getBiometryIcon()}</Text>
        <Text style={styles.title}>Welcome Back</Text>
        <Text style={styles.subtitle}>
          Use {getBiometryLabel()} to sign in securely
        </Text>

        <TouchableOpacity
          style={styles.biometricButton}
          onPress={handleBiometricAuth}
          disabled={isAuthenticating}
        >
          {isAuthenticating ? (
            <ActivityIndicator color="#FFFFFF" />
          ) : (
            <Text style={styles.biometricButtonText}>
              Sign in with {getBiometryLabel()}
            </Text>
          )}
        </TouchableOpacity>

        <TouchableOpacity
          style={styles.passwordButton}
          onPress={navigateToLogin}
          disabled={isAuthenticating}
        >
          <Text style={styles.passwordButtonText}>Use Password Instead</Text>
        </TouchableOpacity>
      </View>

      <View style={styles.securityNote}>
        <Text style={styles.securityNoteText}>
          🔒 Your biometric data never leaves this device.{'\n'}
          Authentication is verified cryptographically with the server.
        </Text>
      </View>
    </View>
  );
}

