// screens/HomeScreen.js
import React, { useState } from 'react';
import {
  View,
  Text,
  TouchableOpacity,
  StyleSheet,
  Alert,
  ScrollView,
} from 'react-native';
import { useAuth } from '../context/AuthContext';

export default function HomeScreen() {
  const {
    logout,
    userId,
    hasBiometricKey,
    biometryType,
    enrollBiometricKey,
    unenrollBiometrics,
  } = useAuth();
  const [isProcessing, setIsProcessing] = useState(false);

  function getBiometryLabel() {
    switch (biometryType) {
      case 'FaceID':
        return 'Face ID';
      case 'TouchID':
        return 'Touch ID';
      case 'Biometrics':
        return 'Fingerprint';
      default:
        return 'Biometrics';
    }
  }

  async function handleLogout() {
    Alert.alert(
      'Sign Out',
      'Do you want to keep biometric login enabled?',
      [
        {
          text: 'Keep & Sign Out',
          onPress: () => logout(false),
        },
        {
          text: 'Remove & Sign Out',
          style: 'destructive',
          onPress: () => logout(true),
        },
        {
          text: 'Cancel',
          style: 'cancel',
        },
      ]
    );
  }

  async function handleToggleBiometrics() {
    setIsProcessing(true);
    try {
      if (hasBiometricKey) {
        const success = await unenrollBiometrics();
        if (success) {
          Alert.alert('Success', `${getBiometryLabel()} has been disabled`);
        } else {
          Alert.alert('Error', 'Failed to disable biometrics');
        }
      } else {
        const success = await enrollBiometricKey();
        if (success) {
          Alert.alert('Success', `${getBiometryLabel()} has been enabled for future logins`);
        } else {
          Alert.alert('Error', 'Failed to enable biometrics');
        }
      }
    } finally {
      setIsProcessing(false);
    }
  }

  return (
    <ScrollView style={styles.container} contentContainerStyle={styles.content}>
      <View style={styles.header}>
        <Text style={styles.greeting}>Welcome! 🎉</Text>
        <Text style={styles.userId}>User: {userId}</Text>
      </View>

      <View style={styles.card}>
        <Text style={styles.cardTitle}>🔒 Authentication Status</Text>
        <Text style={styles.cardText}>
          You are securely authenticated with a server-verified session.
        </Text>
        <View style={styles.statusRow}>
          <Text style={styles.statusLabel}>Session:</Text>
          <Text style={[styles.statusValue, styles.statusActive]}>Active</Text>
        </View>
        <View style={styles.statusRow}>
          <Text style={styles.statusLabel}>{getBiometryLabel()}:</Text>
          <Text
            style={[
              styles.statusValue,
              hasBiometricKey ? styles.statusActive : styles.statusInactive,
            ]}
          >
            {hasBiometricKey ? 'Enrolled' : 'Not Enrolled'}
          </Text>
        </View>
      </View>

      <View style={styles.card}>
        <Text style={styles.cardTitle}>⚙️ Security Settings</Text>

        {biometryType && (
          <TouchableOpacity
            style={styles.settingButton}
            onPress={handleToggleBiometrics}
            disabled={isProcessing}
          >
            <Text style={styles.settingButtonText}>
              {hasBiometricKey
                ? `Disable ${getBiometryLabel()}`
                : `Enable ${getBiometryLabel()}`}
            </Text>
          </TouchableOpacity>
        )}

        {!biometryType && (
          <Text style={styles.noBiometricText}>
            Biometric authentication is not available on this device.
            You can continue using password-based login.
          </Text>
        )}
      </View>

      <View style={styles.card}>
        <Text style={styles.cardTitle}>ℹ️ How It Works</Text>
        <Text style={styles.infoText}>
          • Your biometric data never leaves this device{'\n'}
          • A cryptographic keypair is created in the Secure Enclave / TEE{'\n'}
          • The server verifies a signed challenge — no boolean flags{'\n'}
          • Session tokens are stored in the platform Keychain/Keystore{'\n'}
          • Password fallback requires full server authentication
        </Text>
      </View>

      <TouchableOpacity style={styles.logoutButton} onPress={handleLogout}>
        <Text style={styles.logoutButtonText}>Sign Out</Text>
      </TouchableOpacity>
    </ScrollView>
  );
}

