// server/biometricAuth.js
// Example Node.js/Express server-side implementation
// This shows the backend logic needed to support the secure biometric flow

const express = require('express');
const crypto = require('crypto');
const jwt = require('jsonwebtoken');

const router = express.Router();

const JWT_SECRET = process.env.JWT_SECRET || 'your-secret-key-change-in-production';
const CHALLENGE_EXPIRY_MS = 5 * 60 * 1000; // 5 minutes

// In production, use a proper database
const users = new Map();
const biometricKeys = new Map(); // userId -> publicKey (PEM)
const pendingChallenges = new Map(); // challengeId -> { userId, challenge, expiresAt }

// Middleware to verify JWT
function authenticateToken(req, res, next) {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];

  if (!token) {
    return res.status(401).json({ message: 'Access token required' });
  }

  try {
    const decoded = jwt.verify(token, JWT_SECRET);
    req.user = decoded;
    next();
  } catch (error) {
    return res.status(403).json({ message: 'Invalid or expired token' });
  }
}

// Standard login
router.post('/login', async (req, res) => {
  const { username, password } = req.body;

  // In production: validate against your user database with hashed passwords
  // This is a simplified example
  const user = users.get(username);
  if (!user || !verifyPassword(password, user.passwordHash)) {
    return res.status(401).json({ message: 'Invalid credentials' });
  }

  const token = jwt.sign(
    { userId: user.id, username },
    JWT_SECRET,
    { expiresIn: '24h' }
  );

  res.json({
    success: true,
    token,
    userId: user.id,
  });
});

// Validate session
router.post('/validate', authenticateToken, (req, res) => {
  res.json({ success: true, userId: req.user.userId });
});

// Register biometric public key
router.post('/biometric/register', authenticateToken, (req, res) => {
  const { userId, publicKey } = req.body;

  if (req.user.userId !== userId) {
    return res.status(403).json({ message: 'Unauthorized' });
  }

  // Store the public key associated with the user
  // The public key comes from react-native-biometrics createKeys()
  // It's an RSA public key in PEM format
  biometricKeys.set(userId, {
    publicKey,
    registeredAt: new Date().toISOString(),
  });

  console.log(`Biometric key registered for user ${userId}`);

  res.json({ success: true });
});

// Generate a challenge for biometric authentication
router.post('/biometric/challenge', (req, res) => {
  const { userId } = req.body;

  // Check if user has a registered biometric key
  if (!biometricKeys.has(userId)) {
    return res.status(404).json({
      success: false,
      message: 'No biometric key registered for this user',
    });
  }

  // Generate a random challenge nonce
  const challenge = crypto.randomBytes(32).toString('base64');
  const challengeId = crypto.randomBytes(16).toString('hex');

  // Store the challenge temporarily
  pendingChallenges.set(challengeId, {
    userId,
    challenge,
    expiresAt: Date.now() + CHALLENGE_EXPIRY_MS,
  });

  // Clean up expired challenges periodically
  cleanupExpiredChallenges();

  res.json({
    success: true,
    challenge,
    challengeId,
  });
});

// Verify biometric signature
router.post('/biometric/verify', (req, res) => {
  const { userId, challenge, signature } = req.body;

  // Find the pending challenge
  let foundChallengeId = null;
  for (const [id, data] of pendingChallenges.entries()) {
    if (data.userId === userId && data.challenge === challenge) {
      foundChallengeId = id;
      break;
    }
  }

  if (!foundChallengeId) {
    return res.status(401).json({
      success: false,
      message: 'Invalid or expired challenge',
    });
  }

  const challengeData = pendingChallenges.get(foundChallengeId);

  // Check if challenge has expired
  if (Date.now() > challengeData.expiresAt) {
    pendingChallenges.delete(foundChallengeId);
    return res.status(401).json({
      success: false,
      message: 'Challenge has expired',
    });
  }

  // Get the stored public key for this user
  const keyData = biometricKeys.get(userId);
  if (!keyData) {
    pendingChallenges.delete(foundChallengeId);
    return res.status(401).json({
      success: false,
      message: 'No biometric key found for user',
    });
  }

  try {
    // Verify the signature using the stored public key
    // react-native-biometrics signs with RSA SHA-256
    const verifier = crypto.createVerify('SHA256');
    verifier.update(challenge);
    verifier.end();

    const publicKeyPem = formatPublicKey(keyData.publicKey);
    const isValid = verifier.verify(publicKeyPem, signature, 'base64');

    // Remove the used challenge (one-time use)
    pendingChallenges.delete(foundChallengeId);

    if (!isValid) {
      console.warn(`Invalid biometric signature for user ${userId}`);
      return res.status(401).json({
        success: false,
        message: 'Signature verification failed',
      });
    }

    // Signature is valid — issue a session token
    const user = findUserById(userId);
    const token = jwt.sign(
      { userId, username: user?.username || userId },
      JWT_SECRET,
      { expiresIn: '24h' }
    );

    console.log(`Biometric authentication successful for user ${userId}`);

    res.json({
      success: true,
      token,
      userId,
    });
  } catch (error) {
    console.error('Signature verification error:', error);
    pendingChallenges.delete(foundChallengeId);
    return res.status(500).json({
      success: false,
      message: 'Signature verification error',
    });
  }
});

// Remove biometric key
router.post('/biometric/remove', authenticateToken, (req, res) => {
  const { userId } = req.body;

  if (req.user.userId !== userId) {
    return res.status(403).json({ message: 'Unauthorized' });
  }

  biometricKeys.delete(userId);
  console.log(`Biometric key removed for user ${userId}`);

  res.json({ success: true });
});

// Logout
router.post('/logout', authenticateToken, (req, res) => {
  // In production: add the token to a blacklist or use token revocation
  // For JWT, you might use a Redis-based blacklist
  console.log(`User ${req.user.userId} logged out`);
  res.json({ success: true });
});

// Helper: Format public key to PEM format
function formatPublicKey(key) {
  // react-native-biometrics returns the public key as a base64 string
  // We need to wrap it in PEM headers
  if (key.includes('-----BEGIN')) {
    return key;
  }

  const formatted = key.match(/.{1,64}/g).join('\n');
  return `-----BEGIN PUBLIC KEY-----\n${formatted}\n-----END PUBLIC KEY-----`;
}

// Helper: Clean up expired challenges
function cleanupExpiredChallenges() {
  const now = Date.now();
  for (const [id, data] of pendingChallenges.entries()) {
    if (now > data.expiresAt) {
      pendingChallenges.delete(id);
    }
  }
}

// Helper: Find user by ID (simplified)
function findUserById(userId) {
  for (const [username, user] of users.entries()) {
    if (user.id === userId) {
      return { ...user, username };
    }
  }
  return null;
}

// Helper: Verify password (simplified — use bcrypt in production)
function verifyPassword(password, hash) {
  // In production: use bcrypt.compare(password, hash)
  return crypto.createHash('sha256').update(password).digest('hex') === hash;
}

module.exports = router;